'use client';

import React, { useState } from 'react';
import { 
  Cpu, 
  Send, 
  Sparkles, 
  Copy, 
  Check, 
  RefreshCw, 
  Search, 
  BookOpen, 
  Megaphone, 
  FileText, 
  Mail, 
  Activity, 
  Globe, 
  Key, 
  MessageSquare,
  Mic,
  MicOff,
  Volume2
} from 'lucide-react';

interface Template {
  id: string;
  name: string;
  category: 'SEO' | 'Ads' | 'Social' | 'Strategy' | 'Admin';
  icon: React.ElementType;
  promptLabel: string;
  placeholder: string;
  fields: Array<{ name: string; label: string; type: 'text' | 'textarea' | 'select'; options?: string[]; placeholder?: string }>;
  defaultOutput: string;
}

export const AIDashboardApp: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'chat' | 'templates'>('chat');
  const [selectedModel, setSelectedModel] = useState<string>('Gemini 1.5 Pro');
  
  // Chat state
  const [chatMessages, setChatMessages] = useState<Array<{ sender: 'user' | 'ai'; text: string; time: string }>>([
    { sender: 'ai', text: 'Hello Manoj. I am your Digital Marketing Co-Pilot. I can generate high-converting ad copies, design landing page wireframes, audit metadata, or write competitor SWOT analyses. Which model would you like me to process with?', time: new Date().toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'}) }
  ]);
  const [inputVal, setInputVal] = useState<string>('');
  const [isTyping, setIsTyping] = useState<boolean>(false);
  const [isListening, setIsListening] = useState<boolean>(false);

  const handleVoiceCommand = () => {
    if (isListening) return;
    setIsListening(true);
    setInputVal("Listening... Speak now...");
    setTimeout(() => {
      const voiceQueries = [
        "Optimize my DTC ecommerce ROAS scaling strategy.",
        "Perform a technical SEO traffic checkup audit.",
        "How can I set up custom GA4 lead funnel tracking?",
        "Generate Meta ads hooks targeting eco-friendly products."
      ];
      const randomQuery = voiceQueries[Math.floor(Math.random() * voiceQueries.length)];
      setInputVal(randomQuery);
      setIsListening(false);
    }, 2000);
  };

  // Templates list
  const templates: Template[] = [
    {
      id: 'seo-meta',
      name: 'SEO Metadata Optimizer',
      category: 'SEO',
      icon: Globe,
      promptLabel: 'Target Keyword & URL topic',
      placeholder: 'E.g., "Eco-friendly sneakers for athletes"',
      fields: [
        { name: 'keyword', label: 'Primary Target Keyword', type: 'text', placeholder: 'Eco sneakers' },
        { name: 'tone', label: 'Tone of Voice', type: 'select', options: ['Catchy & Click-worthy', 'Professional & Informative', 'Urgent & Promotional'] }
      ],
      defaultOutput: `=== OPTIMIZED SEO METADATA ===\n\n[Title Tag] (58 characters):\nBest Eco-Friendly Sneakers 2026 | Sustainable Athletic Shoes\n\n[Meta Description] (148 characters):\nDiscover high-performance eco-friendly sneakers crafted from ocean plastic. Engineered for athletes who care about the planet. Shop the collection today!\n\n[H1 Tag Recommendation]:\nPerformance Sneakers That Don't Cost The Earth\n\n[Recommended Alt Text for Hero Banner]:\n"Athlete wearing sustainable white recycled plastic sneakers running on track"`
    },
    {
      id: 'meta-ads',
      name: 'Meta Ads Generator',
      category: 'Ads',
      icon: Megaphone,
      promptLabel: 'Product/Service details & Target Audience',
      placeholder: 'E.g., "Organic coffee subscription box for busy office workers"',
      fields: [
        { name: 'angle', label: 'Hook Angle', type: 'select', options: ['Pain Point (Lack of Sleep)', 'Benefit Driven (Premium Taste)', 'Social Proof (Thousands of Reviews)'] },
        { name: 'discount', label: 'Offer Detail', type: 'text', placeholder: '20% off first box' }
      ],
      defaultOutput: `=== META ADS AD COPY SYSTEM ===\n\n[Primary Text - Hook Angle: Benefit Driven]\n☕ Too busy for coffee runs? Get premium single-origin organic coffee delivered to your desk automatically.\n\nRoasted fresh weekly. Ready in 2 minutes. Free shipping nationwide.\n\n👉 Claim 20% off your first box today: [URL]\n\n[Headline] (Max CTR optimized):\nFresh Organic Coffee, Boxed. (20% Off)\n\n[Description]:\nOver 10,000+ Busy Professionals Fuel Their Day with Us. \n\n[CTA Button]:\nSHOP NOW`
    },
    {
      id: 'keyword-gen',
      name: 'SEO Keyword Generator',
      category: 'SEO',
      icon: Key,
      placeholder: 'E.g., "Digital marketing services in Bangalore"',
      promptLabel: 'Core Seed Topic',
      fields: [
        { name: 'intent', label: 'Target Search Intent', type: 'select', options: ['Transactional (Buying)', 'Informational (Learning)', 'Commercial Investigation'] }
      ],
      defaultOutput: `=== KEYWORD PLANNER REPORT ===\n\nSeed Topic: Digital Marketing Services Bangalore\nTarget Intent: Transactional (High Conversion)\n\n1. "best performance marketing agency in Bangalore" | Vol: 880/mo | KD: 28 (Low-Hanging Fruit)\n2. "hire digital marketing strategist Bangalore" | Vol: 320/mo | KD: 14 (High-Intent)\n3. "Bangalore SEO agency pricing" | Vol: 450/mo | KD: 35 (Commercial)\n4. "technical SEO audit service near Bangalore" | Vol: 150/mo | KD: 9 (Easy Win)\n\n[Recommended Content Hub Strategy]:\nCreate a city-landing page targeting "Bangalore Performance Marketing" and link 4 sub-articles about Google Ads, SEO, and Meta campaign audits.`
    },
    {
      id: 'comp-swot',
      name: 'Competitor SWOT Analyzer',
      category: 'Strategy',
      icon: Activity,
      placeholder: 'Competitor name and niche',
      promptLabel: 'Competitor Profile',
      fields: [
        { name: 'details', label: 'Competitor URL or Description', type: 'text', placeholder: 'CompetitorInc.com' }
      ],
      defaultOutput: `=== COMPETITOR SWOT ANALYSIS ===\n\nTarget: CompetitorInc (Niche E-Commerce)\n\n[STRENGTHS]:\n- Strong organic ranking on informational keywords.\n- High-velocity content strategy (publishing 5 blogs/week).\n\n[WEAKNESSES]:\n- Landing page loading speed is slow (>4.2s), resulting in checkout drops.\n- Zero Google Shopping presence.\n\n[OPPORTUNITIES]:\n- Bid on their branded search keywords in Google Ads.\n- Target their blog articles with high-converting comparison pages ("Manoj Client vs CompetitorInc").\n\n[THREATS]:\n- High capital backing allows them to absorb low-margin CAC.`
    }
  ];

  const [selectedTemplate, setSelectedTemplate] = useState<Template>(templates[0]);
  const [templateInputs, setTemplateInputs] = useState<Record<string, string>>({});
  const [templateOutput, setTemplateOutput] = useState<string>('');
  const [generatingTemplate, setGeneratingTemplate] = useState<boolean>(false);
  const [copied, setCopied] = useState<boolean>(false);

  // Send Chat message
  const handleSendChat = () => {
    if (!inputVal.trim()) return;

    const userMsg = {
      sender: 'user' as const,
      text: inputVal,
      time: new Date().toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})
    };

    setChatMessages(prev => [...prev, userMsg]);
    setInputVal('');
    setIsTyping(true);

    // Mock AI Response depending on keywords
    setTimeout(() => {
      let reply = "I've analyzed your query. To help optimize that, you should run a technical search audit or set up Google Tag Manager conversion pixels. Let me know if you want me to write the copy!";
      
      const query = userMsg.text.toLowerCase();
      if (query.includes('seo') || query.includes('rank')) {
        reply = "For SEO optimization, let's create high-intent content hubs. Build structured schema markups (FAQ & Article schemas) and make sure your primary headers match your search queries. Would you like me to write a title tag set?";
      } else if (query.includes('ads') || query.includes('meta') || query.includes('google')) {
        reply = "For PPC scaling, consolidate your ad sets to let the algorithm optimize conversion events (aim for 50 conversions/week). Use Advantage+ shopping campaigns combined with visual creatives featuring scroll-stopping hook hooks in the first 3 seconds.";
      } else if (query.includes('roi') || query.includes('roas')) {
        reply = "To increase ROAS: 1) Implement post-purchase one-click upsells. 2) Shift bidding to target CPA instead of maximize clicks. 3) Exclude past buyers from cold target audiences.";
      }

      setChatMessages(prev => [...prev, {
        sender: 'ai',
        text: reply,
        time: new Date().toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})
      }]);
      setIsTyping(false);
    }, 1500);
  };

  // Generate Template
  const handleGenerateTemplate = () => {
    setGeneratingTemplate(true);
    setTemplateOutput('');
    
    setTimeout(() => {
      // Return custom output based on template selected or fallback default
      setTemplateOutput(selectedTemplate.defaultOutput);
      setGeneratingTemplate(false);
    }, 1800);
  };

  // Copy to clipboard utility
  const copyOutput = (text: string) => {
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="flex-1 flex overflow-hidden h-full">
      {/* Sidebar - AI Models & Templates */}
      <div className="w-56 border-r border-white/5 bg-black/40 flex flex-col p-4 shrink-0 justify-between select-none">
        <div className="flex flex-col gap-4">
          {/* AI Settings Header */}
          <div className="flex flex-col gap-1 pb-3 border-b border-white/5">
            <label className="text-[9px] text-white/40 uppercase tracking-widest font-bold">Active Engine</label>
            <select 
              value={selectedModel} 
              onChange={(e) => setSelectedModel(e.target.value)}
              className="bg-white/5 border border-white/10 rounded px-2 py-1 text-[11px] text-white font-semibold outline-none cursor-pointer"
            >
              <option value="Claude 3.5 Sonnet" className="bg-slate-900 text-white">Claude 3.5 Sonnet</option>
              <option value="Gemini 1.5 Pro" className="bg-slate-900 text-white">Gemini 1.5 Pro</option>
              <option value="GPT-4o Mini" className="bg-slate-900 text-white">GPT-4o Mini</option>
              <option value="DeepSeek R1" className="bg-slate-900 text-white">DeepSeek R1</option>
              <option value="Grok 2.0" className="bg-slate-900 text-white">Grok 2.0</option>
            </select>
          </div>

          {/* Navigation Buttons */}
          <div className="flex flex-col gap-1">
            <button
              onClick={() => setActiveTab('chat')}
              className={`w-full text-left px-3 py-1.5 rounded-lg text-xs font-semibold flex items-center gap-2 transition-all ${
                activeTab === 'chat' ? 'bg-cyan-500/20 text-cyan-300 border border-cyan-500/30' : 'text-slate-400 hover:bg-white/5'
              }`}
            >
              <MessageSquare className="w-3.5 h-3.5" /> Conversational Copilot
            </button>
            <button
              onClick={() => setActiveTab('templates')}
              className={`w-full text-left px-3 py-1.5 rounded-lg text-xs font-semibold flex items-center gap-2 transition-all ${
                activeTab === 'templates' ? 'bg-cyan-500/20 text-cyan-300 border border-cyan-500/30' : 'text-slate-400 hover:bg-white/5'
              }`}
            >
              <Sparkles className="w-3.5 h-3.5" /> AI Copy Templates
            </button>
          </div>

          {/* Template Lists */}
          {activeTab === 'templates' && (
            <div className="flex flex-col gap-1 border-t border-white/5 pt-3 mt-1">
              <label className="text-[9px] text-white/40 uppercase tracking-widest font-bold mb-1.5 px-2">Assistance Tools</label>
              {templates.map(tpl => {
                const Icon = tpl.icon;
                return (
                  <button
                    key={tpl.id}
                    onClick={() => { setSelectedTemplate(tpl); setTemplateOutput(''); }}
                    className={`w-full text-left px-2 py-1.5 rounded text-[11px] font-medium flex items-center gap-2 transition-colors ${
                      selectedTemplate.id === tpl.id ? 'bg-white/10 text-white font-bold' : 'text-slate-400 hover:bg-white/5'
                    }`}
                  >
                    <Icon className="w-3.5 h-3.5 text-cyan-400/80" />
                    <span className="truncate">{tpl.name}</span>
                  </button>
                );
              })}
            </div>
          )}
        </div>

        {/* Status indicator */}
        <div className="p-3 bg-white/5 border border-white/10 rounded-xl flex items-center gap-2">
          <Cpu className="w-4 h-4 text-cyan-400 animate-pulse" />
          <div>
            <p className="text-[9px] text-white/40">Tokens API Speed</p>
            <p className="text-[10px] text-white font-semibold">120 tokens/sec</p>
          </div>
        </div>
      </div>

      {/* Main Panel Content */}
      <div className="flex-1 flex flex-col overflow-hidden bg-slate-950/20">
        
        {/* CHAT TAB */}
        {activeTab === 'chat' && (
          <div className="flex-grow flex flex-col justify-between overflow-hidden p-6 gap-4">
            
            {/* Chat Header */}
            <div className="flex justify-between items-center border-b border-white/5 pb-3 shrink-0">
              <div>
                <h2 className="font-bold text-sm text-white">Conversational Co-Pilot</h2>
                <p className="text-[10px] text-slate-400">Ask about copywriting rules, keywords bidding, or SEO markup</p>
              </div>
              <span className="px-2.5 py-0.5 rounded-full bg-cyan-500/10 border border-cyan-500/25 text-[9px] text-cyan-400 font-bold uppercase tracking-wider">
                {selectedModel} Ready
              </span>
            </div>

            {/* Chat Messages */}
            <div className="flex-1 overflow-y-auto pr-1 flex flex-col gap-4">
              {chatMessages.map((msg, index) => (
                <div 
                  key={index}
                  className={`flex flex-col max-w-[80%] ${msg.sender === 'user' ? 'self-end items-end' : 'self-start items-start'}`}
                >
                  <span className="text-[9px] text-white/40 mb-1 px-1">{msg.sender === 'user' ? 'You' : 'AI'} • {msg.time}</span>
                  <div className={`p-3 rounded-2xl text-xs leading-relaxed ${
                    msg.sender === 'user' 
                      ? 'bg-cyan-500 text-slate-950 font-medium rounded-tr-none' 
                      : 'bg-white/5 border border-white/5 text-slate-200 rounded-tl-none'
                  }`}>
                    {msg.text}
                  </div>
                </div>
              ))}

              {isTyping && (
                <div className="self-start flex flex-col max-w-[80%]">
                  <span className="text-[9px] text-white/40 mb-1 px-1">AI Agent typing...</span>
                  <div className="p-3 rounded-2xl text-xs bg-white/5 border border-white/5 text-slate-400 rounded-tl-none flex items-center gap-1">
                    <span className="w-1.5 h-1.5 bg-cyan-400 rounded-full animate-bounce"></span>
                    <span className="w-1.5 h-1.5 bg-cyan-400 rounded-full animate-bounce [animation-delay:0.2s]"></span>
                    <span className="w-1.5 h-1.5 bg-cyan-400 rounded-full animate-bounce [animation-delay:0.4s]"></span>
                  </div>
                </div>
              )}
            </div>

            {/* Input Bar */}
            <div className="flex gap-2 shrink-0 border-t border-white/5 pt-3">
              <input 
                type="text"
                value={inputVal}
                onChange={(e) => setInputVal(e.target.value)}
                onKeyDown={(e) => { if(e.key === 'Enter') handleSendChat(); }}
                disabled={isListening}
                placeholder={isListening ? "Listening..." : "Ask your assistant anything (e.g. 'Write a Facebook headline for solar panels')..."}
                className="flex-grow glass-input px-4 py-2.5 text-xs"
              />
              <button 
                onClick={handleVoiceCommand}
                className={`px-3.5 py-2 border rounded-lg flex items-center justify-center cursor-pointer active:scale-95 transition-all ${
                  isListening 
                    ? 'bg-red-500/25 border-red-500/40 text-red-400 font-bold' 
                    : 'glass-button border-white/10 text-slate-300 hover:text-white'
                }`}
                title="Voice controlled assistant"
              >
                {isListening ? <MicOff className="w-4 h-4 animate-pulse" /> : <Mic className="w-4 h-4" />}
              </button>
              <button 
                onClick={handleSendChat}
                className="px-4 py-2 bg-cyan-500 hover:bg-cyan-400 text-slate-950 font-bold rounded-lg flex items-center justify-center cursor-pointer active:scale-95 transition-transform"
              >
                <Send className="w-4 h-4" />
              </button>
            </div>
          </div>
        )}

        {/* TEMPLATES COPY GENERATOR TAB */}
        {activeTab === 'templates' && (
          <div className="flex-1 flex overflow-hidden">
            
            {/* Input Parameters form */}
            <div className="w-72 border-r border-white/5 p-6 flex flex-col justify-between overflow-y-auto shrink-0 select-none">
              <div className="flex flex-col gap-4">
                <div>
                  <h3 className="font-bold text-sm text-white">{selectedTemplate.name}</h3>
                  <p className="text-[10px] text-slate-400">Fill parameters below to generate assets</p>
                </div>

                {/* Fields */}
                <div className="flex flex-col gap-3">
                  <div className="flex flex-col gap-1">
                    <label className="text-[10px] text-white/50">{selectedTemplate.promptLabel}</label>
                    <textarea
                      rows={3}
                      placeholder={selectedTemplate.placeholder}
                      className="glass-input px-3 py-2 text-xs resize-none"
                    />
                  </div>

                  {selectedTemplate.fields.map((f, i) => (
                    <div key={i} className="flex flex-col gap-1">
                      <label className="text-[10px] text-white/50">{f.label}</label>
                      {f.type === 'select' ? (
                        <select className="bg-white/5 border border-white/10 rounded px-2.5 py-1.5 text-xs text-white outline-none cursor-pointer">
                          {f.options?.map((opt, idx) => (
                            <option key={idx} value={opt} className="bg-slate-900 text-white">{opt}</option>
                          ))}
                        </select>
                      ) : (
                        <input 
                          type="text" 
                          placeholder={f.placeholder}
                          className="glass-input px-3 py-1.5 text-xs" 
                        />
                      )}
                    </div>
                  ))}
                </div>
              </div>

              <button
                onClick={handleGenerateTemplate}
                disabled={generatingTemplate}
                className="w-full py-2.5 bg-gradient-to-r from-cyan-500 to-purple-600 hover:from-cyan-400 hover:to-purple-500 text-slate-950 font-bold text-xs rounded-lg flex items-center justify-center gap-1.5 cursor-pointer disabled:opacity-50 transition-all shadow-lg shadow-cyan-500/10"
              >
                {generatingTemplate ? (
                  <>
                    <RefreshCw className="w-3.5 h-3.5 animate-spin" /> Generating...
                  </>
                ) : (
                  <>
                    <Cpu className="w-3.5 h-3.5" /> Generate Copy
                  </>
                )}
              </button>
            </div>

            {/* Output Panel workspace */}
            <div className="flex-1 flex flex-col justify-between p-6 overflow-hidden">
              <div className="flex justify-between items-center border-b border-white/5 pb-2 select-none">
                <span className="text-[10px] text-slate-400 font-semibold uppercase">Generated Marketing Asset</span>
                {templateOutput && (
                  <button
                    onClick={() => copyOutput(templateOutput)}
                    className="glass-button px-2.5 py-1 text-[10px] font-bold flex items-center gap-1 text-cyan-400 border-cyan-500/20"
                  >
                    {copied ? (
                      <>
                        <Check className="w-3 h-3 text-emerald-400" /> Copied!
                      </>
                    ) : (
                      <>
                        <Copy className="w-3 h-3" /> Copy Asset
                      </>
                    )}
                  </button>
                )}
              </div>

              <div className="flex-grow my-4 bg-slate-950/40 border border-white/5 rounded-xl p-4 overflow-y-auto font-mono text-[11px] text-slate-300 whitespace-pre-wrap leading-relaxed">
                {generatingTemplate ? (
                  <div className="w-full h-full flex flex-col items-center justify-center text-slate-400 gap-2">
                    <div className="w-6 h-6 border-2 border-cyan-400 border-t-transparent rounded-full animate-spin" />
                    <p className="text-[10px] uppercase font-bold tracking-widest text-cyan-400 animate-pulse">Running {selectedModel} pipeline...</p>
                  </div>
                ) : templateOutput ? (
                  templateOutput
                ) : (
                  <div className="w-full h-full flex flex-col items-center justify-center text-slate-500 text-center gap-2 select-none">
                    <Sparkles className="w-8 h-8 text-white/10" />
                    <p>Adjust parameters on the left and click &quot;Generate Copy&quot; to run AI agents.</p>
                  </div>
                )}
              </div>

              <div className="text-[9px] text-slate-500 select-none">
                Tip: Copy-paste generated templates directly into your ad campaign manager or website CMS settings.
              </div>
            </div>

          </div>
        )}

      </div>
    </div>
  );
};
